{
  "sentences": [
    {
      "text": "你現在在做什麼？",
      "pinyin": "Nǐ xiànzài zài zuò shénme?",
      "pinyin_numeric": "ni3 xian4zai4 zai4 zuo4 shen2me0",
      "translation_en": "What are you doing now?",
      "translation_ko": "지금 무엇을 하고 계세요?"
    },
    {
      "text": "我正在看書。",
      "pinyin": "Wǒ zhèngzài kàn shū.",
      "pinyin_numeric": "wo3 zheng4zai4 kan4 shu1",
      "translation_en": "I am reading a book.",
      "translation_ko": "저는 책을 보고 있어요."
    },
    {
      "text": "他在上網。",
      "pinyin": "Tā zài shàngwǎng.",
      "pinyin_numeric": "ta1 zai4 shang4wang3",
      "translation_en": "He is surfing the internet.",
      "translation_ko": "그는 인터넷을 하고 있어요."
    },
    {
      "text": "她正在滑手機。",
      "pinyin": "Tā zhèngzài huá shǒujī.",
      "pinyin_numeric": "ta1 zheng4zai4 hua2 shou3ji1",
      "translation_en": "She is scrolling on her phone.",
      "translation_ko": "그녀는 핸드폰을 보고 있어요."
    },
    {
      "text": "你現在在忙嗎？",
      "pinyin": "Nǐ xiànzài zài máng ma?",
      "pinyin_numeric": "ni3 xian4zai4 zai4 mang2 ma0",
      "translation_en": "Are you busy now?",
      "translation_ko": "지금 바쁘세요?"
    },
    {
      "text": "我現在不行，我正在開會。",
      "pinyin": "Wǒ xiànzài bùxíng, wǒ zhèngzài kāihuì.",
      "pinyin_numeric": "wo3 xian4zai4 bu4xing2, wo3 zheng4zai4 kai1hui4",
      "translation_en": "I can't now, I am in a meeting.",
      "translation_ko": "지금 안 돼요, 회의 중이에요."
    },
    {
      "text": "他在傳訊息給朋友。",
      "pinyin": "Tā zài chuán xùnxī gěi péngyǒu.",
      "pinyin_numeric": "ta1 zai4 chuan2 xun4xi1 gei3 peng2you3",
      "translation_en": "He is sending a message to a friend.",
      "translation_ko": "그는 친구에게 메시지를 보내고 있어요."
    },
    {
      "text": "她正在寫功課。",
      "pinyin": "Tā zhèngzài xiě gōngkè.",
      "pinyin_numeric": "ta1 zheng4zai4 xie3 gong1ke4",
      "translation_en": "She is doing homework.",
      "translation_ko": "그녀는 숙제를 하고 있어요."
    },
    {
      "text": "你等一下見，我還在路上。",
      "pinyin": "Nǐ děng yīxià jiàn, wǒ hái zài lùshàng.",
      "pinyin_numeric": "ni3 deng3 yi1xia4 jian4, wo3 hai2 zai4 lu4shang4",
      "translation_en": "See you later, I am still on the way.",
      "translation_ko": "잠시 후에 봐요, 저는 아직 가는 중이에요."
    },
    {
      "text": "不好意思打擾，你現在方便嗎？",
      "pinyin": "Bù hǎoyìsi dǎrǎo, nǐ xiànzài fāngbiàn ma?",
      "pinyin_numeric": "bu4 hao3yi4si0 da3rao3, ni3 xian4zai4 fang1bian4 ma0",
      "translation_en": "Sorry to bother you, are you free now?",
      "translation_ko": "방해해서 죄송한데, 지금 괜찮으세요?"
    }
  ]
}
